import React, { useEffect } from 'react'
import useData from './data';
import TableProvider, { useTableContext } from './Provider';
import './style.css'

export function TableHeader () {
    const { headers } = useTableContext() 
    if(headers) {
    return (
        <thead>
            <tr>
                {headers.map(header => (<th>{header}</th>))}
            </tr>
        </thead>
    )
    }
}

export function TableBody() {
    const { searchedData } = useTableContext()
    if(searchedData) {
    return (
    <tbody>
        {searchedData.map(item => <tr key={item?.id}>
            {Object.keys(item).map((itemKey) => <td key={`${item?.id}_${item?.title}`}>{item[itemKey]}</td>)}
        </tr>)}
    </tbody>
    )
    }
}

export function Search() {
  const { searchText, onSearchHandler } = useTableContext()
  function searchHandler(e) {
    console.log('e', e.target.value)
    onSearchHandler(e.target.value)
  }
  return (
    <input name="Search" type='search' value={searchText} onChange={searchHandler} />
  )
}

export function Table() {
  const { loading, error, tableData } = useData();
  const { setTableData, getHeaders } = useTableContext()
  useEffect(() => {
   if(tableData) {
      setTableData(tableData)
      getHeaders(tableData[0])
   }
  },[tableData])

  return (
    <>
    <Search />
    <table>
        <TableHeader/>
        <TableBody/>
    </table>
    </>
  )
}

function TableContainer() {
    return (
        <TableProvider>
            <Table />
        </TableProvider>
    )
}

export default TableContainer
